  function applyTheme(persist){var resolved=themeMode==="system"?(themeMedia&&themeMedia.matches?"dark":"light"):themeMode;document.documentElement.dataset.theme=resolved;var toggle=document.getElementById("theme-toggle");var label=themeMode==="dark"?T("다크"):themeMode==="light"?T("라이트"):T("시스템");if(toggle){toggle.lastElementChild.textContent=T("테마: ")+label;toggle.setAttribute("aria-label",T("테마: ")+label);}if(persist){try{localStorage.setItem("nautli-theme",themeMode);}catch(error){}}window.dispatchEvent(new CustomEvent("nautli-theme-change",{detail:{mode:themeMode,resolved:resolved}}));}
