      options=options||{};
      var actionLabel=entry.action==="merge"?T("중복 합침"):entry.action==="remember"?T("자동 기억"):entry.action==="shadow"?T("지켜보는 중"):entry.action==="a_wins"||entry.action==="b_wins"||entry.action==="newer_wins"?T("모순 해결"):esc(entry.action);
