      var scope=entry.scope?esc(scopeLabel(entry.scope)):'';
      var conf=entry.confidence!=null?T("확신")+' '+Math.round(Number(entry.confidence)*100)+'%':'';
      var time=entry.applied_at?entry.applied_at.slice(0,10):'';
      var claimText='';
